arguments.new_str:
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainerService>();

var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

// Train the model at startup so the .zip file exists before first prediction
var trainer = app.Services.GetRequiredService<ModelTrainerService>();
trainer.TrainAndSaveModel();

app.MapControllers();
app.Run();

